CREATE TABLE IF NOT EXISTS media_items (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NOT NULL REFERENCES tenants(id) ON DELETE CASCADE, instagram_account_id BIGINT NOT NULL REFERENCES instagram_accounts(id) ON DELETE CASCADE, platform_media_id TEXT, media_type TEXT NOT NULL CHECK (media_type IN ('image','video','carousel','reel','story','unknown')), caption TEXT, published_at TIMESTAMPTZ, raw_json JSONB, UNIQUE (tenant_id, platform_media_id));
